  // =========================================================================
  // array
  // =========================================================================
  test("array") {
    assertCompresses(
      input = """var a;
        function f(b) {
            Math.floor(a / b);
            Math.floor(c / b);
        }""".stripMargin.trim,
      expected = """var a;
        function f(b) {
            c;
        }""".stripMargin.trim,
      options = AllOff.copy(
        pureFuncs = List("Math.floor"),
        sideEffects = true
      )
    )
  }

