        unused = true
      )
    )
  }

  // =========================================================================
  // conditional
  // =========================================================================
  test("conditional") {
    assertCompresses(
      input = """pure(1 | a() ? 2 & b() : 7 ^ c());
        pure(1 | a() ? 2 & b() : 5);
        pure(1 | a() ? 4 : 7 ^ c());
        pure(1 | a() ? 4 : 5);
        pure(3 ? 2 & b() : 7 ^ c());
        pure(3 ? 2 & b() : 5);
        pure(3 ? 4 : 7 ^ c());
        pure(3 ? 4 : 5)""".stripMargin.trim,
      expected = """1 | a() ? b() : c();
        1 | a() && b();
        1 | a() || c();
        a();
        3 ? b() : c();
        3 && b();
        3 || c()""".stripMargin.trim,
      options = AllOff.copy(
        pureFuncs = List("pure"),
        sideEffects = true
      )
    )
  }

