        "bar" >= "bar"""".stripMargin.trim,
      expected = """bar();
        bar();
        bar(), bar();
        bar();
        bar()""".stripMargin.trim,
      options = AllOff.copy(
        pureFuncs = List("foo"),
        sideEffects = true
      )
    )
  }

